function remove(idx: number) {
  const pathName = toValue(arrayPath);
  const pathValue = getFromPath<TValue[]>(form?.values, pathName);
  if (!pathValue || !Array.isArray(pathValue)) {
    return;
  }

  const newValue = [...pathValue];
  newValue.splice(idx, 1);
  const fieldPath = pathName + `[${idx}]`;
  form.destroyPath(fieldPath);
  form.unsetInitialValue(fieldPath);
  setInPath(form.values, pathName, newValue);
  fields.value.splice(idx, 1);
  afterMutation();
}

function push(initialValue: TValue) {
  const value = deepCopy(initialValue);
  const pathName = toValue(arrayPath);
  const pathValue = getFromPath<TValue[]>(form?.values, pathName);
  const normalizedPathValue = isNullOrUndefined(pathValue) ? [] : pathValue;
  if (!Array.isArray(normalizedPathValue)) {
    return;
  }

  const newValue = [...normalizedPathValue];
  newValue.push(value);
  form.stageInitialValue(pathName + `[${newValue.length - 1}]`, value);
  setInPath(form.values, pathName, newValue);
  fields.value.push(createEntry(value));
  afterMutation();
}

function swap(indexA: number, indexB: number) {
  const pathName = toValue(arrayPath);
  const pathValue = getFromPath<TValue[]>(form?.values, pathName);
  if (!Array.isArray(pathValue) || !(indexA in pathValue) || !(indexB in pathValue)) {
    return;
  }

  const newValue = [...pathValue];
  const newFields = [...fields.value];

  const temp = newValue[indexA];
  newValue[indexA] = newValue[indexB];
  newValue[indexB] = temp;

  const tempEntry = newFields[indexA];
  newFields[indexA] = newFields[indexB];
  newFields[indexB] = tempEntry;
  setInPath(form.values, pathName, newValue);
  fields.value = newFields;
  updateEntryFlags();
}

function insert(idx: number, initialValue: TValue) {
  const value = deepCopy(initialValue);
  const pathName = toValue(arrayPath);
  const pathValue = getFromPath<TValue[]>(form?.values, pathName);
  if (!Array.isArray(pathValue) || pathValue.length < idx) {
    return;
  }

  const newValue = [...pathValue];
  const newFields = [...fields.value];

  newValue.splice(idx, 0, value);
  newFields.splice(idx, 0, createEntry(value));
  setInPath(form.values, pathName, newValue);
  fields.value = newFields;
  afterMutation();
}

import type { VNode, VNodeChild } from 'vue'
import { Comment, createTextVNode, Fragment } from 'vue'

// o(n) flatten
export function flatten(
  vNodes: VNodeChild[],
  filterCommentNode: boolean = true,
  result: VNode[] = []
): VNode[] {
  vNodes.forEach((vNode) => {
    if (vNode === null)
      return
    if (typeof vNode !== 'object') {
      if (typeof vNode === 'string' || typeof vNode === 'number') {
        result.push(createTextVNode(String(vNode)))
      }
      return
    }
    if (Array.isArray(vNode)) {
      flatten(vNode, filterCommentNode, result)
      return
    }
    if (vNode.type === Fragment) {
      if (vNode.children === null)
        return
      if (Array.isArray(vNode.children)) {
        flatten(vNode.children, filterCommentNode, result)
      }
      // rawSlot
    }
    else {
      if (vNode.type === Comment && filterCommentNode)
        return
      result.push(vNode)
    }
  })
  return result
}

export function mergeProps(...args: (Data & VNodeProps)[]): Data {
  const ret: Data = {}
  for (let i = 0; i < args.length; i++) {
    const toMerge = args[i]
    for (const key in toMerge) {
      if (key === 'class') {
        if (ret.class !== toMerge.class) {
          ret.class = normalizeClass([ret.class, toMerge.class])
        }
      } else if (key === 'style') {
        ret.style = normalizeStyle([ret.style, toMerge.style])
      } else if (isOn(key)) {
        const existing = ret[key]
        const incoming = toMerge[key]
        if (
          incoming &&
          existing !== incoming &&
          !(isArray(existing) && existing.includes(incoming))
        ) {
          ret[key] = existing
            ? [].concat(existing as any, incoming as any)
            : incoming
        } else if (
          incoming == null &&
          existing == null &&
          // mergeProps({ 'onUpdate:modelValue': undefined }) should not retain
          // the model listener.
          !isModelListener(key)
        ) {
          ret[key] = incoming
        }
      } else if (key !== '') {
        ret[key] = toMerge[key]
      }
    }
  }
  return ret
}

