export const classNameToArray = (cls = '') =>
  cls.split(' ').filter((item) => !!item.trim())

export const hasClass = (el: Element, cls: string): boolean => {
  if (!el || !cls) return false
  if (cls.includes(' ')) throw new Error('className should not contain space.')
  return el.classList.contains(cls)
}

export const addClass = (el: Element, cls: string) => {
  if (!el || !cls.trim()) return
  el.classList.add(...classNameToArray(cls))
}

export const removeClass = (el: Element, cls: string) => {
  if (!el || !cls.trim()) return
  el.classList.remove(...classNameToArray(cls))
}

export const getStyle = (
  element: HTMLElement,
  styleName: keyof CSSProperties
): string => {
  if (!isClient || !element || !styleName || isShadowRoot(element)) return ''

  let key = camelize(styleName)
  if (key === 'float') key = 'cssFloat'
  try {
    const style = (element.style as any)[key]
    if (style) return style
    const computed: any = document.defaultView?.getComputedStyle(element, '')
    return computed ? computed[key] : ''
  } catch {
    return (element.style as any)[key]
  }
}

export function useFileFilter (props: FileFilterProps) {
  const fileFilter = computed(() => props.filterByType ? createFilter(props.filterByType) : null)

  function filterAccepted (files: File[]): FileFilterResult {
    if (fileFilter.value) {
      const accepted = files.filter(fileFilter.value)
      return {
        accepted,
        rejected: files.filter(f => !accepted.includes(f)),
      }
    }
    return {
      accepted: files,
      rejected: [],
    }
  }

  return {
    filterAccepted,
  }
}

function createFilter (v: string): ((v: File) => boolean) {
  const types = v.split(',').map(x => x.trim().toLowerCase())
  const extensionsToMatch = types.filter(x => x.startsWith('.'))
  const wildcards = types.filter(x => x.endsWith('/*'))
  const typesToMatch = types.filter(x => !extensionsToMatch.includes(x) && !wildcards.includes(x))

  return (file: File): boolean => {
    const extension = file.name.split('.').at(-1)?.toLowerCase() ?? ''
    const typeGroup = file.type.split('/').at(0)?.toLowerCase() ?? ''
    return typesToMatch.includes(file.type) ||
      extensionsToMatch.includes(`.${extension}`) ||
      wildcards.includes(`${typeGroup}/*`)
  }
}

export function useFileDrop () {
  function getTransfer (e: DragEvent | ClipboardEvent): DataTransfer | null {
    return (e as DragEvent).dataTransfer ?? (e as ClipboardEvent).clipboardData ?? null
  }

  function hasFilesOrFolders (e: DragEvent | ClipboardEvent): boolean {
    const transfer = getTransfer(e)
    const entries = [...transfer?.items ?? []]
      .filter(x => x.kind === 'file')
      .map(x => x.webkitGetAsEntry())
      .filter(Boolean)

    return entries.length > 0 || [...transfer?.files ?? []].length > 0
  }

  async function handleDrop (e: DragEvent | ClipboardEvent) {
    const transfer = getTransfer(e)
    const result: File[] = []

    const entries = [...transfer?.items ?? []]
      .filter(x => x.kind === 'file')
      .map(x => x.webkitGetAsEntry())
      .filter(Boolean)

    if (entries.length) {
      for (const entry of entries) {
        const files = await traverseFileTree(entry!, appendIfDirectory('.', entry!))
        result.push(...files.map(x => x.file))
      }
    } else {
      result.push(...[...transfer?.files ?? []])
    }

    return result
  }

  return {
    handleDrop,
    hasFilesOrFolders,
  }
}

